import akka.actor.{Actor, ActorRef, ActorSystem, Props}
import scala.concurrent.stm._

// Message protocol
sealed trait AccountMessage
case class Deposit(amount: BigDecimal, replyTo: ActorRef) extends AccountMessage
case class Withdraw(amount: BigDecimal, replyTo: ActorRef) extends AccountMessage
case class GetBalance(replyTo: ActorRef) extends AccountMessage
