// Response protocol
sealed trait AccountResponse
case class DepositSuccess(newBalance: BigDecimal) extends AccountResponse
case class WithdrawSuccess(newBalance: BigDecimal) extends AccountResponse
case class WithdrawFailure(reason: String, currentBalance: BigDecimal) extends AccountResponse
case class BalanceResponse(balance: BigDecimal) extends AccountResponse
case class TransferSuccess(newBalance: BigDecimal) extends AccountResponse
case class TransferFailure(reason: String) extends AccountResponse

// Account actor using STM (Software Transactional Memory) for safe concurrent access
class AccountActor(accountId: String, initialBalance: BigDecimal = BigDecimal(0)) extends Actor {

  // Using STM Ref instead of a plain var for thread-safe atomic read-modify-write operations.
  // A plain `var balance` without synchronization is UNSAFE even inside an actor if any
  // external code or future callbacks access it. STM provides composable atomic transactions.
  private val balance: Ref[BigDecimal] = Ref(initialBalance)

  override def receive: Receive = {
    case Deposit(amount, replyTo) =>
      if (amount <= 0) {
        replyTo ! WithdrawFailure(s"Invalid deposit amount: $amount", atomic { implicit txn => balance() })
      } else {
        val newBalance = atomic { implicit txn =>
          val current = balance()
          val updated = current + amount
          balance() = updated
          updated
        }
        replyTo ! DepositSuccess(newBalance)
      }

    case Withdraw(amount, replyTo) =>
      if (amount <= 0) {
        replyTo ! WithdrawFailure(s"Invalid withdrawal amount: $amount", atomic { implicit txn => balance() })
      } else {
        val result = atomic { implicit txn =>
          val current = balance()
          if (current >= amount) {
            val updated = current - amount
            balance() = updated
            Right(updated)
          } else {
            Left((s"Insufficient funds. Current balance: $current, requested: $amount", current))
          }
        }
        result match {
          case Right(newBalance) => replyTo ! WithdrawSuccess(newBalance)
          case Left((reason, currentBalance)) => replyTo ! WithdrawFailure(reason, currentBalance)
        }
      }

    case GetBalance(replyTo) =>
      val currentBalance = atomic { implicit txn =>
        balance()
      }
      replyTo ! BalanceResponse(currentBalance)

    case Transfer(amount, toAccount, replyTo) =>
      if (amount <= 0) {
        replyTo ! TransferFailure(s"Invalid transfer amount: $amount")
      } else {
        val result = atomic { implicit txn =>
          val current = balance()
          if (current >= amount) {
            balance() = current - amount
            Right(current - amount)
          } else {
            Left(s"Insufficient funds for transfer. Current balance: $current, requested: $amount")
          }
        }
        result match {
          case Right(newBalance) =>
            // Send deposit to the target account
            toAccount ! Deposit(amount, self)
            replyTo ! TransferSuccess(newBalance)
          case Left(reason) =>
            replyTo ! TransferFailure(reason)
        }
      }
  }
}

